import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, Check, ChevronRight, RefreshCw, Sparkles, AlertCircle, ArrowLeft, Sun, Shield, Award, FlipHorizontal, Lock, Eye, Info, ScanFace, User, Mail, Phone } from 'lucide-react';

/**
 * Dental Visualizer App - Make.com Integration Version
 * * A premium dental simulation tool for patient engagement.
 * * ARCHITECTURE: 
 * * 1. Frontend captures image and builds the prompt.
 * * 2. Data is sent to Make.com Webhook.
 * * 3. Make.com processes with AI and returns the result.
 */

// --- Configuration & Constants ---

const TREATMENTS = [
  { 
    id: 'veneers', 
    title: 'Porcelain Veneers', 
    desc: 'Hollywood smile transformation',
    // Structural: Allowed to change shape, but must fit in mouth
    promptContext: "ACTION: Replace visible teeth with high-end porcelain veneers. GOAL: Perfect symmetry, closed gaps, and ideal Golden Ratio proportions. TEXTURE: Glass-like polish.",
    structuralChange: true, 
    icon: <Sparkles className="w-6 h-6" />
  },
  { 
    id: 'implants', 
    title: 'Dental Implants', 
    desc: 'Permanent tooth replacement',
    // Structural: Fill gaps
    promptContext: "ACTION: Fill any visible gaps or missing teeth with dental implants. GOAL: Restore full dental arch. ANATOMY: Ensure natural emergence profile from the gums.",
    structuralChange: true,
    icon: <Shield className="w-6 h-6" />
  },
  { 
    id: 'all-on-x', 
    title: 'All-on-4® / All-on-6', 
    desc: 'Full jaw restoration',
    // Structural: Full reconstruction
    promptContext: "ACTION: Reconstruct the entire dental arch (All-on-4). GOAL: Uniform, youthful, and straight teeth alignment. ALIGNMENT: Perfectly parallel to the interpupillary line.",
    structuralChange: true,
    icon: <Award className="w-6 h-6" />
  },
  { 
    id: 'whitening', 
    title: 'Laser Whitening', 
    desc: 'Brighten natural teeth',
    // Non-Structural: Color only
    promptContext: "ACTION: Perform professional teeth whitening. GOAL: Remove yellow staining. CONSTRAINT: Preserve original tooth morphology, chips, and gaps exactly. DO NOT straighten.",
    structuralChange: false,
    icon: <Sun className="w-6 h-6" />
  },
  { 
    id: 'crowns', 
    title: 'Zirconia Crowns', 
    desc: 'Strength and aesthetics',
    // Structural: Cap existing teeth
    promptContext: "ACTION: Place Zirconia crowns on visible teeth. GOAL: Restore volume and structure. TEXTURE: High-strength ceramic, slightly less translucent than veneers.",
    structuralChange: true,
    icon: <div className="w-6 h-6 font-bold text-center border rounded-full text-xs flex items-center justify-center">Zr</div>
  }
];

const MATERIALS = {
  veneers: [
    { id: 'emax', title: 'E.max® Laminates', desc: 'High translucency, glass-ceramic look', promptMod: "MATERIAL_TYPE: Lithium Disilicate (E.max). OPTICAL_PROPERTIES: High translucency at incisal edges. Blue-ish tint at tips, warm at neck." },
    { id: 'zirconia', title: 'Ultra-Thin Zirconia', desc: 'High strength, pure white potential', promptMod: "MATERIAL_TYPE: Zirconia. OPTICAL_PROPERTIES: High opacity, high brightness value, very solid white appearance. Reflective surface." },
    { id: 'lumineers', title: 'Lumineers®', desc: 'Ultra-thin, non-prep look', promptMod: "MATERIAL_TYPE: Cerinate Porcelain. OPTICAL_PROPERTIES: Slightly rounded contours, very smooth surface, conservative bulk." }
  ],
  implants: [
    { id: 'straumann', title: 'Straumann® (Swiss)', desc: 'Premium Swiss porcelain finish', promptMod: "STYLE: High-end Swiss aesthetic. DETAILS: Natural gum integration, fine surface texture." },
    { id: 'nobel', title: 'Nobel Biocare®', desc: 'Natural contouring', promptMod: "STYLE: Biomimetic. DETAILS: Mimics natural tooth layers and gradual shading." },
    { id: 'megagen', title: 'MegaGen', desc: 'Standard high-quality', promptMod: "STYLE: Clean cosmetic look. DETAILS: Bright, standard Hollywood white finish." }
  ],
  'all-on-x': [
    { id: 'straumann-pro', title: 'Straumann Pro Arch', desc: 'Full arch ceramic', promptMod: "CONFIGURATION: Monolithic Zirconia Bridge. LOOK: Continuous aesthetic, perfect symmetry, high gloss glaze." },
    { id: 'nobel-all-on-4', title: 'Nobel All-on-4®', desc: 'Acrylic/Hybrid finish', promptMod: "CONFIGURATION: Hybrid Denture. LOOK: Pink gum simulation where necessary, uniform white teeth." }
  ],
  whitening: [
    { id: 'zoom', title: 'Philips Zoom!', desc: 'High gloss bright white', promptMod: "INTENSITY: High. FINISH: Glossy enamel. TARGET: Remove deep stains." },
    { id: 'laser', title: 'Biolase Laser', desc: 'Natural soft white', promptMod: "INTENSITY: Medium-High. FINISH: Satin/Pearl. TARGET: Even out tone." }
  ],
  crowns: [
    { id: 'zirconia-monolithic', title: 'Monolithic Zirconia', desc: 'Opaque, extreme durability', promptMod: "MATERIAL: Full contour Zirconia. OPACITY: 100%. LOOK: Solid, bright, uniform." },
    { id: 'pfm', title: 'Porcelain Fused Metal', desc: 'Classic layered look', promptMod: "MATERIAL: Feldspathic Porcelain over Metal. OPACITY: 80%. LOOK: Depth of color, slightly warmer near gingiva." }
  ]
};

const SHADES = [
  { id: 'bl1', title: 'BL1', desc: 'Hollywood Bleach (Extra White)', promptMod: "SHADE_CODE: BL1. COLOR_DESC: Bleached white, paper white, highest value. No yellow." },
  { id: 'bl3', title: 'BL3', desc: 'Bright White (Soft Bleach)', promptMod: "SHADE_CODE: BL3. COLOR_DESC: Soft bleach, bright white but natural looking. Minimal saturation." },
  { id: 'b1', title: 'B1', desc: 'Natural White (Lightest Natural)', promptMod: "SHADE_CODE: B1. COLOR_DESC: Lightest natural ivory. Hint of cream." },
  { id: 'a1', title: 'A1', desc: 'Light Natural', promptMod: "SHADE_CODE: A1. COLOR_DESC: Natural white, healthy enamel tone. Very slight reddish-brown hue." },
  { id: 'a2', title: 'A2', desc: 'Warm Natural', promptMod: "SHADE_CODE: A2. COLOR_DESC: Average natural tooth, warm ivory, realistic saturation." }
];

// --- Sub-components (DEFINED FIRST TO FIX REFERENCE ERRORS) ---

function OptionCard({ title, desc, icon, onClick }) {
  return (
    <button 
      onClick={onClick}
      className="w-full text-left p-4 bg-white rounded-xl border border-slate-200 shadow-sm hover:border-blue-500 hover:ring-1 hover:ring-blue-500 transition-all group"
    >
      <div className="flex items-start space-x-4">
        <div className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center flex-shrink-0 mt-1 group-hover:bg-blue-600 group-hover:text-white transition-colors">
          {icon || <div className="w-2 h-2 rounded-full bg-current" />}
        </div>
        <div className="flex-1">
          <h3 className="font-semibold text-slate-900 text-lg">{title}</h3>
          <p className="text-sm text-slate-500 leading-relaxed">{desc}</p>
        </div>
        <ChevronRight className="w-5 h-5 text-slate-300 self-center group-hover:text-blue-500" />
      </div>
    </button>
  );
}

function ReviewRow({ label, value }) {
  return (
    <div className="flex justify-between items-center border-b border-slate-100 last:border-0 pb-2 last:pb-0">
      <span className="text-slate-500 text-sm">{label}</span>
      <span className="font-medium text-slate-900 text-sm">{value}</span>
    </div>
  );
}

/**
 * BeforeAfterSlider
 */
function BeforeAfterSlider({ original, simulation }) {
  const [sliderPosition, setSliderPosition] = useState(50);
  const containerRef = useRef(null);

  const handleDrag = (e) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
    const percent = Math.max(0, Math.min(100, (x / rect.width) * 100));
    setSliderPosition(percent);
  };

  const handleTouch = (e) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const touch = e.touches[0];
    const x = Math.max(0, Math.min(touch.clientX - rect.left, rect.width));
    const percent = Math.max(0, Math.min(100, (x / rect.width) * 100));
    setSliderPosition(percent);
  };

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-[4/5] rounded-2xl overflow-hidden cursor-ew-resize select-none shadow-xl"
      onMouseMove={(e) => e.buttons === 1 && handleDrag(e)}
      onTouchMove={handleTouch}
      onClick={handleDrag}
    >
      {/* Background Image (Simulation/After) */}
      <img 
        src={simulation} 
        alt="After" 
        className="absolute inset-0 w-full h-full object-cover pointer-events-none" 
      />

      {/* Foreground Image (Original/Before) */}
      <div 
        className="absolute inset-0 w-full h-full overflow-hidden pointer-events-none"
        style={{ clipPath: `inset(0 ${100 - sliderPosition}% 0 0)` }}
      >
        <img 
          src={original} 
          alt="Before" 
          className="absolute inset-0 w-full h-full object-cover" 
        />
      </div>

      {/* Slider Handle */}
      <div 
        className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize flex items-center justify-center shadow-[0_0_10px_rgba(0,0,0,0.5)]"
        style={{ left: `${sliderPosition}%` }}
      >
        <div className="w-8 h-8 bg-white rounded-full shadow-lg flex items-center justify-center text-blue-600">
          <div className="flex space-x-0.5">
            <div className="w-0.5 h-3 bg-current opacity-50"></div>
            <div className="w-0.5 h-3 bg-current opacity-50"></div>
          </div>
        </div>
      </div>

      {/* Labels */}
      <div className="absolute top-4 left-4 bg-black/50 backdrop-blur text-white text-[10px] font-bold px-2 py-1 rounded pointer-events-none">BEFORE</div>
      <div className="absolute top-4 right-4 bg-blue-600/80 backdrop-blur text-white text-[10px] font-bold px-2 py-1 rounded pointer-events-none">AFTER</div>
    </div>
  );
}

/**
 * CameraModule
 */
function CameraModule({ onCapture }) {
  const [stream, setStream] = useState(null);
  const [facingMode, setFacingMode] = useState('user'); 
  const videoRef = useRef(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    return () => stopCamera();
  }, []);

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  const startCamera = async (overrideMode) => {
    const modeToUse = overrideMode || facingMode;

    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Browser does not support camera access");
      }

      const constraints = { 
        video: { 
          facingMode: modeToUse 
        },
        audio: false
      };

      const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(mediaStream);

      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        try {
          await videoRef.current.play();
        } catch (playErr) {
          console.error("Video play error:", playErr);
        }
      }
    } catch (err) {
      console.error("Camera error:", err);
    }
  };

  const toggleCamera = () => {
    const newMode = facingMode === 'user' ? 'environment' : 'user';
    setFacingMode(newMode);
    startCamera(newMode);
  };

  const takePhoto = () => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');

    if (facingMode === 'user') {
      ctx.translate(canvas.width, 0);
      ctx.scale(-1, 1);
    }

    ctx.drawImage(videoRef.current, 0, 0);
    const dataUrl = canvas.toDataURL('image/jpeg');
    stopCamera();
    onCapture(dataUrl);
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onCapture(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="fixed inset-0 bg-black z-50 flex flex-col animate-fade-in">
      <div className="relative flex-1 bg-black overflow-hidden flex items-center justify-center">
        {stream ? (
          <video 
            ref={videoRef} 
            playsInline 
            muted 
            className={`absolute inset-0 w-full h-full object-cover ${facingMode === 'user' ? 'scale-x-[-1]' : ''}`}
          />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center text-slate-500 flex-col space-y-4 p-4 text-center">
             <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center text-slate-700">
               <Camera className="w-8 h-8" />
             </div>
             <p className="max-w-xs">Camera inactive. Click "Enable Camera" or upload a photo.</p>
          </div>
        )}

        <div className="absolute inset-0 pointer-events-none">
           <div className="absolute inset-0 bg-black/50" 
                style={{ 
                  maskImage: 'radial-gradient(ellipse 220px 300px at center, transparent 1%, black 100%)',
                  WebkitMaskImage: 'radial-gradient(ellipse 220px 300px at center, transparent 1%, black 100%)' 
                }}>
           </div>

           <div className="absolute inset-0 flex items-center justify-center">
             <div className="w-[280px] h-[400px] border-2 border-white/30 rounded-[50%] relative">
                {stream && (
                  <div className="absolute top-0 left-0 right-0 h-1 bg-blue-500/80 shadow-[0_0_15px_rgba(59,130,246,0.8)] animate-scan"></div>
                )}
                <div className="absolute top-8 left-1/2 -translate-x-1/2 text-white/90 font-medium text-sm drop-shadow-md">
                   Center your smile
                </div>
             </div>
           </div>
        </div>
      </div>

      <div className="bg-black/90 p-8 pb-12 flex items-center justify-between space-x-4">
         <button 
           onClick={() => fileInputRef.current.click()}
           className="p-4 rounded-full bg-white/10 text-white hover:bg-white/20 transition-all active:scale-95"
           aria-label="Upload Photo"
         >
           <Upload className="w-6 h-6" />
         </button>
         <input 
           type="file" 
           ref={fileInputRef} 
           className="hidden" 
           accept="image/*" 
           onChange={handleFileUpload}
         />

         {stream ? (
           <button 
             onClick={takePhoto}
             className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center relative group active:scale-95 transition-transform"
             aria-label="Take Photo"
           >
             <div className="w-16 h-16 bg-white rounded-full group-hover:scale-90 transition-transform" />
           </button>
         ) : (
           <button 
             onClick={() => startCamera()}
             className="px-6 py-3 bg-blue-600 rounded-full text-white font-bold whitespace-nowrap active:scale-95 transition-transform"
           >
             Enable Camera
           </button>
         )}

         {stream ? (
           <button 
             onClick={toggleCamera}
             className="p-4 rounded-full bg-white/10 text-white hover:bg-white/20 transition-all active:scale-95"
             aria-label="Switch Camera"
           >
             <RefreshCw className="w-6 h-6" />
           </button>
         ) : (
           <div className="w-14" />
         )}
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 10%; opacity: 0; }
          10% { opacity: 1; }
          90% { opacity: 1; }
          100% { top: 90%; opacity: 0; }
        }
        .animate-scan {
          animation: scan 3s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
}

// --- Main Application Component (NOW AT THE END) ---

export default function App() {
  const [step, setStep] = useState(0); 
  const [selection, setSelection] = useState({ treatment: null, material: null, shade: null });
  const [hasConsented, setHasConsented] = useState(false);
  const [image, setImage] = useState(null); 
  const [isSimulating, setIsSimulating] = useState(false);
  const [resultImage, setResultImage] = useState(null);
  const [error, setError] = useState(null);

  const handleSelect = (key, value) => {
    setSelection(prev => ({ ...prev, [key]: value }));
    nextStep();
  };

  const nextStep = () => setStep(prev => prev + 1);
  const prevStep = () => setStep(prev => Math.max(0, prev - 1));

  const handleImageCapture = (imgData) => {
    setImage(imgData);
    nextStep();
  };

  const generateSimulation = async () => {
    setIsSimulating(true);
    setError(null);

    // ------------------------------------------------------------------
    // CONFIGURATION: PASTE YOUR MAKE.COM WEBHOOK URL HERE
    // ------------------------------------------------------------------
    const webhookUrl = "YOUR_MAKE_COM_WEBHOOK_URL_HERE"; 
    // ------------------------------------------------------------------

    // Guard Clause
    if (!webhookUrl || webhookUrl === "YOUR_MAKE_COM_WEBHOOK_URL_HERE" || !webhookUrl.startsWith("http")) {
        setTimeout(() => {
            setError("Configuration Required: Please replace 'YOUR_MAKE_COM_WEBHOOK_URL_HERE' in the code with your actual Make.com Webhook URL to generate real results.");
            setIsSimulating(false);
        }, 1000);
        return;
    }

    try {
      if (!image) throw new Error("No image data available to simulate.");

      const treatmentContext = selection.treatment?.promptContext || "Improve the smile.";
      const materialContext = selection.material?.promptMod || "";
      const shadeContext = selection.shade?.promptMod || "White and bright";

      const isWhitening = selection.treatment?.id === 'whitening';

      let anatomicalDirectives = "";
      if (isWhitening) {
        anatomicalDirectives = `
          [STRICT ANATOMY LOCK]
          - DO NOT change the shape of the teeth.
          - DO NOT change the length of the teeth.
          - DO NOT close any gaps (diastema).
          - DO NOT straighten crooked teeth.
          - PRESERVE all original chips, rotations, and positions.
          - FOCUS ONLY on the pixel color value (Whiteness/Brightness).
        `;
      } else {
        anatomicalDirectives = `
          [ANATOMY OPTIMIZATION]
          - CORRECT alignment: Straighten crooked teeth.
          - CORRECT proportions: Ensure teeth follow the Golden Ratio.
          - CORRECT symmetry: Mirror the left and right sides.
          - CONSTRAINT: Must fit STRICTLY within the existing lip frame. Do not morph the lips.
        `;
      }

      const prompt = `
        ** SYSTEM INSTRUCTIONS: DENTAL SIMULATION ENGINE **

        [ROLE]
        You are an advanced medical imaging AI specializing in aesthetic dentistry.

        [TASK]
        Perform a realistic dental simulation on the user's photo.

        [INPUT PROTECTION - CRITICAL]
        - IDENTITY: The face (eyes, nose, skin, chin, ears, hair) MUST be identical to the original.
        - LIPS: The lip shape and mouth opening MUST be identical to the original.
        - LIGHTING: The lighting direction and intensity on the teeth must match the rest of the face.

        [TREATMENT SPECS]
        - PROCEDURE: ${selection.treatment?.title}
        - INSTRUCTIONS: ${treatmentContext}

        [MATERIAL SPECS]
        - ${materialContext}

        [COLOR SPECS]
        - ${shadeContext}

        [GEOMETRY RULES]
        ${anatomicalDirectives}

        [OUTPUT STYLE]
        - Photorealistic
        - High-definition medical imagery
        - Natural reflection map (wetness on teeth)
      `;

      const payload = {
        image: image.split(',')[1], 
        prompt: prompt,
        metadata: {
            treatment: selection.treatment?.title,
            material: selection.material?.title,
            shade: selection.shade?.title
        }
      };

      const response = await fetch(webhookUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        }
      );

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Webhook Error (${response.status}): ${response.statusText}`);
      }

      const data = await response.json();

      let generatedBase64 = null;
      if (data.image) generatedBase64 = data.image;
      else if (data.data) generatedBase64 = data.data;
      else if (data.output) generatedBase64 = data.output;

      if (generatedBase64) {
        const finalImage = generatedBase64.startsWith('data:image') 
          ? generatedBase64 
          : `data:image/png;base64,${generatedBase64}`;

        setResultImage(finalImage);
      } else {
        throw new Error("No image data found in webhook response.");
      }

    } catch (err) {
      console.error(err);
      setError("Simulation failed. " + err.message);
    } finally {
      setIsSimulating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 selection:bg-blue-100">
      {step > 0 && (
        <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
          <div className="max-w-md mx-auto px-4 h-16 flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-blue-900 rounded-lg flex items-center justify-center text-white font-bold text-xl">D</div>
              <span className="font-bold text-lg tracking-tight text-blue-950">DENTAKAY<span className="text-blue-500 font-light">VISUALS</span></span>
            </div>
            <div className="flex items-center space-x-2">
              <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide">Preview Mode</span>
            </div>
          </div>
          <div className="h-1 bg-slate-100 w-full">
            <div 
              className="h-full bg-blue-600 transition-all duration-500 ease-out" 
              style={{ width: `${(step / 7) * 100}%` }}
            />
          </div>
        </header>
      )}

      <main className={`max-w-md mx-auto ${step === 0 ? 'h-screen' : 'px-4 py-6 pb-24'}`}>

        {step > 1 && step < 7 && (
          <button 
            onClick={prevStep}
            className="mb-4 flex items-center text-sm text-slate-500 hover:text-blue-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-1" /> Back
          </button>
        )}

        {/* --- STEP 0: INTRO SCREEN --- */}
        {step === 0 && (
          <div className="h-full flex flex-col items-center justify-center p-6 bg-gradient-to-br from-blue-950 via-slate-900 to-black text-white relative overflow-hidden animate-fade-in">
            <div className="absolute top-0 left-0 w-64 h-64 bg-blue-500/20 rounded-full blur-3xl -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-0 right-0 w-80 h-80 bg-purple-500/10 rounded-full blur-3xl translate-x-1/3 translate-y-1/3"></div>

            <div className="z-10 text-center space-y-8 max-w-sm">
               <div className="w-16 h-16 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center text-white font-bold text-3xl mx-auto border border-white/20 shadow-2xl">
                 D
               </div>

               <div className="space-y-4">
                 <h1 className="text-4xl font-bold tracking-tight leading-tight">
                   See Your Future <span className="text-blue-400">Smile</span>
                 </h1>
                 <p className="text-slate-300 text-lg font-light leading-relaxed">
                   Experience your dental transformation instantly using AI. Private. Immediate. No appointments needed.
                 </p>
               </div>

               <div className="py-8">
                 <button 
                   onClick={nextStep}
                   className="group relative w-full py-4 px-8 bg-white text-blue-950 rounded-full font-bold text-lg shadow-[0_0_20px_rgba(255,255,255,0.3)] hover:shadow-[0_0_30px_rgba(255,255,255,0.5)] transition-all overflow-hidden"
                 >
                   <span className="relative z-10 flex items-center justify-center">
                     Start Visualisation
                     <ChevronRight className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform" />
                   </span>
                   <div className="absolute inset-0 bg-blue-50 opacity-0 group-hover:opacity-100 transition-opacity" />
                 </button>
               </div>

               <div className="flex items-center justify-center space-x-6 text-slate-400 text-xs font-medium">
                 <div className="flex items-center">
                   <Shield className="w-3 h-3 mr-1.5" />
                   GDPR Safe
                 </div>
                 <div className="flex items-center">
                   <ScanFace className="w-3 h-3 mr-1.5" />
                   No Data Stored
                 </div>
                 <div className="flex items-center">
                   <Sparkles className="w-3 h-3 mr-1.5" />
                   AI Powered
                 </div>
               </div>
            </div>
          </div>
        )}

        {/* --- STEP 1: TREATMENT --- */}
        {step === 1 && (
          <div className="animate-fade-in">
