                    >
                      Demo Mode: Skip this step
                    </button>
                 </div>
              </div>
            )}
          </div>
        )}

        {/* --- STEP 7: FINAL RESULT --- */}
        {step === 7 && (
          <div className="animate-fade-in h-full flex flex-col">
              <div className="flex flex-col h-full">
                <div className="flex items-center justify-between mb-4">
                  <h1 className="text-2xl font-bold text-slate-900">Your New Smile</h1>
                  <span className="bg-green-100 text-green-700 text-xs font-bold px-2 py-1 rounded-full uppercase tracking-wide">AI Simulation</span>
                </div>

                {/* Before / After Slider */}
                <div className="mb-6">
                  <BeforeAfterSlider original={image} simulation={resultImage} />
                  <div className="flex justify-between mt-2 text-xs text-slate-400 px-1">
