import React, { useState } from 'react';
import { 
  Check, ChevronRight, RefreshCw, Sparkles, AlertCircle, ArrowLeft, 
  Lock, Info, ScanFace, User, Mail, Shield
} from 'lucide-react';

import OptionCard from './components/OptionCard';
import ReviewRow from './components/ReviewRow';
import BeforeAfterSlider from './components/BeforeAfterSlider';
import CameraModule from './components/CameraModule';
import { TREATMENTS, MATERIALS, SHADES } from './constants';
import { SelectionState, Treatment, Material, Shade, WebhookPayload } from './types';

export default function App() {
  const [step, setStep] = useState(0); 
  const [selection, setSelection] = useState<SelectionState>({ treatment: null, material: null, shade: null });
  const [hasConsented, setHasConsented] = useState(false);
  const [image, setImage] = useState<string | null>(null); 
  const [isSimulating, setIsSimulating] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSelect = (key: keyof SelectionState, value: Treatment | Material | Shade) => {
    setSelection(prev => ({ ...prev, [key]: value }));
    nextStep();
  };

  const nextStep = () => setStep(prev => prev + 1);
  const prevStep = () => setStep(prev => Math.max(0, prev - 1));

  const handleImageCapture = (imgData: string) => {
    setImage(imgData);
    nextStep();
  };

  const generateSimulation = async () => {
    setIsSimulating(true);
    setError(null);

    // ------------------------------------------------------------------
    // CONFIGURATION: PASTE YOUR MAKE.COM WEBHOOK URL HERE
    // ------------------------------------------------------------------
    const webhookUrl: string = "YOUR_MAKE_COM_WEBHOOK_URL_HERE"; 
    // ------------------------------------------------------------------

    // Guard Clause
    if (!webhookUrl || webhookUrl === "YOUR_MAKE_COM_WEBHOOK_URL_HERE" || !webhookUrl.startsWith("http")) {
        setTimeout(() => {
            setError("Configuration Required: Please replace 'YOUR_MAKE_COM_WEBHOOK_URL_HERE' in App.tsx with your actual Make.com Webhook URL.");
            setIsSimulating(false);
        }, 1000);
        return;
    }

    try {
      if (!image) throw new Error("No image data available to simulate.");

      const treatmentContext = selection.treatment?.promptContext || "Improve the smile.";
      const materialContext = selection.material?.promptMod || "";
      const shadeContext = selection.shade?.promptMod || "White and bright";

      const isWhitening = selection.treatment?.id === 'whitening';

      let anatomicalDirectives = "";
      if (isWhitening) {
        anatomicalDirectives = `
          [STRICT ANATOMY LOCK]
          - DO NOT change the shape of the teeth.
          - DO NOT change the length of the teeth.
          - DO NOT close any gaps (diastema).
          - DO NOT straighten crooked teeth.
          - PRESERVE all original chips, rotations, and positions.
          - FOCUS ONLY on the pixel color value (Whiteness/Brightness).
        `;
      } else {
        anatomicalDirectives = `
          [ANATOMY OPTIMIZATION]
          - CORRECT alignment: Straighten crooked teeth.
          - CORRECT proportions: Ensure teeth follow the Golden Ratio.
          - CORRECT symmetry: Mirror the left and right sides.
          - CONSTRAINT: Must fit STRICTLY within the existing lip frame. Do not morph the lips.
        `;
      }

      const prompt = `
        ** SYSTEM INSTRUCTIONS: DENTAL SIMULATION ENGINE **

        [ROLE]
        You are an advanced medical imaging AI specializing in aesthetic dentistry.

        [TASK]
        Perform a realistic dental simulation on the user's photo.

        [INPUT PROTECTION - CRITICAL]
        - IDENTITY: The face (eyes, nose, skin, chin, ears, hair) MUST be identical to the original.
        - LIPS: The lip shape and mouth opening MUST be identical to the original.
        - LIGHTING: The lighting direction and intensity on the teeth must match the rest of the face.

        [TREATMENT SPECS]
        - PROCEDURE: ${selection.treatment?.title}
        - INSTRUCTIONS: ${treatmentContext}

        [MATERIAL SPECS]
        - ${materialContext}

        [COLOR SPECS]
        - ${shadeContext}

        [GEOMETRY RULES]
        ${anatomicalDirectives}

        [OUTPUT STYLE]
        - Photorealistic
        - High-definition medical imagery
        - Natural reflection map (wetness on teeth)
      `;

      const payload: WebhookPayload = {
        image: image.split(',')[1], 
        prompt: prompt,
        metadata: {
            treatment: selection.treatment?.title,
            material: selection.material?.title,
            shade: selection.shade?.title
        }
      };

      const response = await fetch(webhookUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        }
      );

      if (!response.ok) {
        throw new Error(`Webhook Error (${response.status}): ${response.statusText}`);
      }

      const data = await response.json();

      let generatedBase64 = null;
      if (data.image) generatedBase64 = data.image;
      else if (data.data) generatedBase64 = data.data;
      else if (data.output) generatedBase64 = data.output;

      if (generatedBase64) {
        const finalImage = generatedBase64.startsWith('data:image') 
          ? generatedBase64 
          : `data:image/png;base64,${generatedBase64}`;

        setResultImage(finalImage);
      } else {
        throw new Error("No image data found in webhook response.");
      }

    } catch (err: any) {
      console.error(err);
      setError("Simulation failed. " + (err.message || "Unknown error"));
    } finally {
      setIsSimulating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 selection:bg-blue-100">
      {step > 0 && (
        <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
          <div className="max-w-md mx-auto px-4 h-16 flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-blue-900 rounded-lg flex items-center justify-center text-white font-bold text-xl">D</div>
              <span className="font-bold text-lg tracking-tight text-blue-950">DENTAKAY<span className="text-blue-500 font-light">VISUALS</span></span>
            </div>
            <div className="flex items-center space-x-2">
              <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide">Preview Mode</span>
            </div>
          </div>
          <div className="h-1 bg-slate-100 w-full">
            <div 
              className="h-full bg-blue-600 transition-all duration-500 ease-out" 
              style={{ width: `${(step / 7) * 100}%` }}
            />
          </div>
        </header>
      )}

      <main className={`max-w-md mx-auto ${step === 0 ? 'h-screen' : 'px-4 py-6 pb-24'}`}>

        {step > 1 && step < 7 && (
          <button 
            onClick={prevStep}
            className="mb-4 flex items-center text-sm text-slate-500 hover:text-blue-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-1" /> Back
          </button>
        )}

        {/* --- STEP 0: INTRO SCREEN --- */}
        {step === 0 && (
          <div className="h-full flex flex-col items-center justify-center p-6 bg-gradient-to-br from-blue-950 via-slate-900 to-black text-white relative overflow-hidden animate-fade-in">
            <div className="absolute top-0 left-0 w-64 h-64 bg-blue-500/20 rounded-full blur-3xl -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-0 right-0 w-80 h-80 bg-purple-500/10 rounded-full blur-3xl translate-x-1/3 translate-y-1/3"></div>

            <div className="z-10 text-center space-y-8 max-w-sm">
               <div className="w-16 h-16 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center text-white font-bold text-3xl mx-auto border border-white/20 shadow-2xl">
                 D
               </div>

               <div className="space-y-4">
                 <h1 className="text-4xl font-bold tracking-tight leading-tight">
                   See Your Future <span className="text-blue-400">Smile</span>
                 </h1>
                 <p className="text-slate-300 text-lg font-light leading-relaxed">
                   Experience your dental transformation instantly using AI. Private. Immediate. No appointments needed.
                 </p>
               </div>

               <div className="py-8">
                 <button 
                   onClick={nextStep}
                   className="group relative w-full py-4 px-8 bg-white text-blue-950 rounded-full font-bold text-lg shadow-[0_0_20px_rgba(255,255,255,0.3)] hover:shadow-[0_0_30px_rgba(255,255,255,0.5)] transition-all overflow-hidden"
                 >
                   <span className="relative z-10 flex items-center justify-center">
                     Start Visualisation
                     <ChevronRight className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform" />
                   </span>
                   <div className="absolute inset-0 bg-blue-50 opacity-0 group-hover:opacity-100 transition-opacity" />
                 </button>
               </div>

               <div className="flex items-center justify-center space-x-6 text-slate-400 text-xs font-medium">
                 <div className="flex items-center">
                   <Shield className="w-3 h-3 mr-1.5" />
                   GDPR Safe
                 </div>
                 <div className="flex items-center">
                   <ScanFace className="w-3 h-3 mr-1.5" />
                   No Data Stored
                 </div>
                 <div className="flex items-center">
                   <Sparkles className="w-3 h-3 mr-1.5" />
                   AI Powered
                 </div>
               </div>
            </div>
          </div>
        )}

        {/* --- STEP 1: TREATMENT --- */}
        {step === 1 && (
          <div className="animate-fade-in">
            <h1 className="text-2xl font-bold text-slate-900 mb-2">Select Treatment</h1>
            <p className="text-slate-500 mb-6">Choose the procedure you are interested in.</p>
            <div className="space-y-3">
              {TREATMENTS.map((t) => (
                <OptionCard 
                  key={t.id} 
                  title={t.title} 
                  desc={t.desc} 
                  icon={t.icon}
                  onClick={() => handleSelect('treatment', t)} 
