                >
                  <div className={`w-12 h-12 rounded-full border-2 border-slate-100 shadow-inner mr-4 flex-shrink-0 bg-gradient-to-br from-white to-slate-100`} 
                       style={{ 
                         backgroundColor: s.id === 'bl1' ? '#ffffff' : s.id === 'a2' ? '#fefce0' : '#fffdf5' 
