}

import React, { useState } from 'react';
import { 
  Check, ChevronRight, RefreshCw, Sparkles, AlertCircle, ArrowLeft, 
  Lock, Info, ScanFace, User, Mail, Shield
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

import OptionCard from './components/OptionCard';
import ReviewRow from './components/ReviewRow';
import BeforeAfterSlider from './components/BeforeAfterSlider';
import CameraModule from './components/CameraModule';
import { TREATMENTS, MATERIALS, SHADES } from './constants';
import { SelectionState, Treatment, Material, Shade } from './types';

export default function App() {
  const [step, setStep] = useState(0); 
  const [selection, setSelection] = useState<SelectionState>({ treatment: null, material: null, shade: null });
  const [hasConsented, setHasConsented] = useState(false);
  const [image, setImage] = useState<string | null>(null); 
  const [isSimulating, setIsSimulating] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSelect = (key: keyof SelectionState, value: Treatment | Material | Shade) => {
    setSelection(prev => ({ ...prev, [key]: value }));
    nextStep();
  };

  const nextStep = () => setStep(prev => prev + 1);
  const prevStep = () => setStep(prev => Math.max(0, prev - 1));

  const handleImageCapture = (imgData: string) => {
    setImage(imgData);
    nextStep();
  };

  const generateSimulation = async () => {
    setIsSimulating(true);
    setError(null);

    try {
      if (!image) throw new Error("No image data available to simulate.");

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const treatmentContext = selection.treatment?.promptContext || "Improve the smile.";
      const materialContext = selection.material?.promptMod || "";
      const shadeContext = selection.shade?.promptMod || "White and bright";

      const isWhitening = selection.treatment?.id === 'whitening';

      let anatomicalDirectives = "";

      if (isWhitening) {
        // STRONG constraints for whitening to prevent hallucinating new teeth shapes
        anatomicalDirectives = `
          [TASK TYPE: IMAGE RECOLORING / FILTER]
          - STRICT GEOMETRY LOCK: You are FORBIDDEN from changing the shape, size, or alignment of the teeth.
          - PRESERVE IMPERFECTIONS: Every gap (diastema), chip, rotation, and crooked tooth MUST remain exactly as it is in the original image.
          - ACTION: Apply a whitening color adjustment ONLY to the existing enamel pixels.
          - FAILURE CONDITION: If the teeth look straighter or different in shape, the generation is failed.
        `;
      } else {
        // Standard reconstruction rules for other treatments
        anatomicalDirectives = `
          [TASK TYPE: AESTHETIC RECONSTRUCTION]
          - ALIGNMENT: Straighten crooked teeth to create a harmonious arc.
          - PROPORTIONS: Restore missing volume and ensure Golden Ratio proportions.
          - SYMMETRY: Balance the left and right sides.
          - CONSTRAINT: Respect the original lip frame boundaries.
        `;
      }

      const prompt = `
        ** SYSTEM INSTRUCTIONS: DENTAL VISUALIZATION **

        [INPUT]
        The user has provided a photo of their current smile.

        [MANDATORY CONSTRAINTS]
        1. IDENTITY: The face, skin, lips, and lighting MUST be pixel-perfect identical to the original.
        2. LIPS: Do NOT change the mouth opening or lip shape.

        [SELECTED PROCEDURE]
        ${selection.treatment?.title}

        [INSTRUCTIONS]
        ${treatmentContext}

        [MATERIAL & SHADE]
        ${materialContext}
        ${shadeContext}

        [GEOMETRY RULES - HIGHEST PRIORITY]
        ${anatomicalDirectives}

        [OUTPUT]
        A photorealistic image with the requested dental changes applied.
      `;

      // Extract MIME type and base64 data
      const matches = image.match(/^data:(.+);base64,(.+)$/);
      let mimeType = 'image/jpeg';
      let base64Data = image;

      if (matches && matches.length === 3) {
        mimeType = matches[1];
        base64Data = matches[2];
      } else {
        // Fallback or handle raw base64 if necessary
        base64Data = image.replace(/^data:image\/\w+;base64,/, "");
      }

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: mimeType,
                data: base64Data
              }
            },
            {
              text: prompt
            }
          ]
        }
      });

      let generatedBase64 = null;

      // Iterate through parts to find the image
      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            generatedBase64 = part.inlineData.data;
            // Capture mimeType if available, otherwise assume png (common for Gemini output)
            const outMime = part.inlineData.mimeType || 'image/png';
            setResultImage(`data:${outMime};base64,${generatedBase64}`);
            break;
          }
        }
      }

      if (!generatedBase64) {
        // If no image part was found, look for text that might explain the refusal
        const textOutput = response.text;
        if (textOutput) {
             throw new Error("AI Refusal: " + textOutput);
        }
        throw new Error("No image generated. The model might have filtered the response due to safety settings.");
      }

    } catch (err: any) {
      console.error(err);
      setError("Simulation failed. " + (err.message || "Unknown error"));
    } finally {
      setIsSimulating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 selection:bg-blue-100">
      {step > 0 && (
        <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
          <div className="max-w-md mx-auto px-4 h-16 flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-blue-900 rounded-lg flex items-center justify-center text-white font-bold text-xl">D</div>
              <span className="font-bold text-lg tracking-tight text-blue-950">DENTAKAY<span className="text-blue-500 font-light">VISUALS</span></span>
            </div>
            <div className="flex items-center space-x-2">
              <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wide">Preview Mode</span>
            </div>
          </div>
          <div className="h-1 bg-slate-100 w-full">
            <div 
              className="h-full bg-blue-600 transition-all duration-500 ease-out" 
              style={{ width: `${(step / 7) * 100}%` }}
            />
          </div>
        </header>
      )}

      <main className={`max-w-md mx-auto ${step === 0 ? 'h-screen' : 'px-4 py-6 pb-24'}`}>

        {step > 1 && step < 7 && (
          <button 
            onClick={prevStep}
            className="mb-4 flex items-center text-sm text-slate-500 hover:text-blue-600 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 mr-1" /> Back
          </button>
        )}

        {/* --- STEP 0: INTRO SCREEN --- */}
        {step === 0 && (
          <div className="h-full flex flex-col items-center justify-center p-6 bg-gradient-to-br from-blue-950 via-slate-900 to-black text-white relative overflow-hidden animate-fade-in">
            <div className="absolute top-0 left-0 w-64 h-64 bg-blue-500/20 rounded-full blur-3xl -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-0 right-0 w-80 h-80 bg-purple-500/10 rounded-full blur-3xl translate-x-1/3 translate-y-1/3"></div>

            <div className="z-10 text-center space-y-8 max-w-sm">
               <div className="w-16 h-16 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center text-white font-bold text-3xl mx-auto border border-white/20 shadow-2xl">
                 D
               </div>

               <div className="space-y-4">
                 <h1 className="text-4xl font-bold tracking-tight leading-tight">
                   See Your Future <span className="text-blue-400">Smile</span>
                 </h1>
                 <p className="text-slate-300 text-lg font-light leading-relaxed">
                   Experience your dental transformation instantly using AI. Private. Immediate. No appointments needed.
                 </p>
               </div>

               <div className="py-8">
                 <button 
                   onClick={nextStep}
                   className="group relative w-full py-4 px-8 bg-white text-blue-950 rounded-full font-bold text-lg shadow-[0_0_20px_rgba(255,255,255,0.3)] hover:shadow-[0_0_30px_rgba(255,255,255,0.5)] transition-all overflow-hidden"
                 >
                   <span className="relative z-10 flex items-center justify-center">
                     Start Visualisation
                     <ChevronRight className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform" />
                   </span>
                   <div className="absolute inset-0 bg-blue-50 opacity-0 group-hover:opacity-100 transition-opacity" />
                 </button>
               </div>

               <div className="flex items-center justify-center space-x-6 text-slate-400 text-xs font-medium">
                 <div className="flex items-center">
                   <Shield className="w-3 h-3 mr-1.5" />
                   GDPR Safe
                 </div>
                 <div className="flex items-center">
                   <ScanFace className="w-3 h-3 mr-1.5" />
                   No Data Stored
                 </div>
                 <div className="flex items-center">
                   <Sparkles className="w-3 h-3 mr-1.5" />
                   AI Powered
                 </div>
               </div>
            </div>
          </div>
        )}

        {/* --- STEP 1: TREATMENT --- */}
        {step === 1 && (
          <div className="animate-fade-in">
            <h1 className="text-2xl font-bold text-slate-900 mb-2">Select Treatment</h1>
            <p className="text-slate-500 mb-6">Choose the procedure you are interested in.</p>
            <div className="space-y-3">
              {TREATMENTS.map((t) => (
                <OptionCard 
                  key={t.id} 
                  title={t.title} 
                  desc={t.desc} 
                  icon={t.icon}
                  onClick={() => handleSelect('treatment', t)} 
                />
              ))}
            </div>
          </div>
        )}

        {/* --- STEP 2: MATERIAL --- */}
        {step === 2 && (
          <div className="animate-fade-in">
            <h1 className="text-2xl font-bold text-slate-900 mb-2">Select Material</h1>
            <p className="text-slate-500 mb-6">Preferred brand or material for {selection.treatment?.title}.</p>
            <div className="space-y-3">
              {(selection.treatment && MATERIALS[selection.treatment.id] ? MATERIALS[selection.treatment.id] : MATERIALS.veneers).map((m) => (
                <OptionCard 
                  key={m.id} 
                  title={m.title} 
                  desc={m.desc} 
                  onClick={() => handleSelect('material', m)} 
                />
              ))}
            </div>
          </div>
        )}

        {/* --- STEP 3: SHADE --- */}
        {step === 3 && (
          <div className="animate-fade-in">
            <h1 className="text-2xl font-bold text-slate-900 mb-2">Select Shade</h1>
            <p className="text-slate-500 mb-6">From Hollywood bright to natural aesthetics.</p>
            <div className="grid grid-cols-1 gap-3">
              {SHADES.map((s) => (
                <button
                  key={s.id}
                  onClick={() => handleSelect('shade', s)}
                  className="group relative flex items-center p-4 bg-white rounded-xl border border-slate-200 shadow-sm hover:border-blue-500 hover:shadow-md transition-all text-left"
                >
                  <div className={`w-12 h-12 rounded-full border-2 border-slate-100 shadow-inner mr-4 flex-shrink-0 bg-gradient-to-br from-white to-slate-100`} 
                       style={{ 
                         backgroundColor: s.id === 'bl1' ? '#ffffff' : s.id === 'a2' ? '#fefce0' : '#fffdf5' 
                       }} 
                  />
                  <div>
                    <div className="font-semibold text-slate-900">{s.title}</div>
                    <div className="text-sm text-slate-500">{s.desc}</div>
                  </div>
                  <ChevronRight className="w-5 h-5 ml-auto text-slate-300 group-hover:text-blue-500" />
                </button>
              ))}
            </div>
          </div>
        )}

        {/* --- STEP 4: CONSENT & CAMERA --- */}
        {step === 4 && (
          <div className="animate-fade-in h-full">
            {!hasConsented ? (
               <div className="flex flex-col h-full pt-4">
                 <div className="bg-blue-50 border border-blue-100 rounded-2xl p-6 mb-6">
                   <div className="w-12 h-12 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 mb-4">
                     <Lock className="w-6 h-6" />
                   </div>
                   <h2 className="text-lg font-bold text-slate-900 mb-2">Privacy & Consent</h2>
                   <p className="text-sm text-slate-600 mb-4 leading-relaxed">
                     To generate your smile preview, we need to process your photo temporarily.
                   </p>
                   <ul className="space-y-3 mb-6">
                     <li className="flex items-start text-sm text-slate-700">
                       <Check className="w-4 h-4 text-green-500 mr-2 mt-0.5 shrink-0" />
                       <span>Your photo is processed temporarily for this simulation only.</span>
                     </li>
                     <li className="flex items-start text-sm text-slate-700">
                       <Check className="w-4 h-4 text-green-500 mr-2 mt-0.5 shrink-0" />
                       <span>We do not store your face data for identification.</span>
                     </li>
                     <li className="flex items-start text-sm text-slate-700">
                       <Check className="w-4 h-4 text-green-500 mr-2 mt-0.5 shrink-0" />
                       <span>This is a visual preview, <strong>not a medical diagnosis</strong>.</span>
                     </li>
                   </ul>

                   <label className="flex items-start space-x-3 p-3 bg-white rounded-lg border border-slate-200 cursor-pointer hover:border-blue-400 transition-colors">
                      <input type="checkbox" className="mt-1 w-4 h-4 text-blue-600 rounded border-slate-300 focus:ring-blue-500" 
                        onChange={(e) => {
                          if(e.target.checked) setHasConsented(true);
                        }}
                      />
                      <span className="text-xs text-slate-500 font-medium">
                        I consent to Dentakay temporarily processing my photo to generate a visual simulation. I understand I can request deletion at any time.
                      </span>
                   </label>
                 </div>
                 <div className="text-center">
                    <button 
                      disabled={!hasConsented}
                      onClick={() => {}} 
                      className={`px-6 py-3 rounded-full font-bold w-full transition-colors ${hasConsented ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
                    >
                      {hasConsented ? 'Continue to Camera' : 'Accept to Continue'}
                    </button>
                    <p className="text-xs text-slate-400 mt-4">Dentakay protects your data under GDPR standards.</p>
                 </div>
               </div>
            ) : (
              <CameraModule onCapture={handleImageCapture} />
            )}
          </div>
        )}

        {/* --- STEP 5: REVIEW --- */}
        {step === 5 && (
          <div className="animate-fade-in">
             <h1 className="text-2xl font-bold text-slate-900 mb-2">Ready to Visualize?</h1>
             <p className="text-slate-500 mb-6">We will simulate your new smile.</p>

             <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-6 space-y-3">
               <ReviewRow label="Treatment" value={selection.treatment?.title} />
               <ReviewRow label="Material" value={selection.material?.title} />
               <ReviewRow label="Shade" value={`${selection.shade?.title} - ${selection.shade?.desc}`} />
             </div>

             <div className="relative aspect-[3/4] bg-slate-100 rounded-xl overflow-hidden mb-6 border border-slate-200">
                {image && <img src={image} alt="Original" className="w-full h-full object-cover" />}
                <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/70 to-transparent p-4">
                  <p className="text-white text-sm font-medium">Original Photo</p>
                </div>
             </div>

             <button 
               onClick={() => { nextStep(); generateSimulation(); }}
               className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-lg shadow-lg shadow-blue-200 transition-all flex items-center justify-center space-x-2"
             >
               <Sparkles className="w-5 h-5" />
               <span>Generate Smile</span>
             </button>
             <p className="text-xs text-slate-400 text-center mt-3">
               By clicking Generate, you agree to our Terms of Service.
             </p>
          </div>
        )}

        {/* --- STEP 6: PROCESSING & LEAD GATE --- */}
        {step === 6 && (
          <div className="animate-fade-in h-full flex flex-col">
            {isSimulating ? (
              /* LOADING STATE */
              <div className="flex-1 flex flex-col items-center justify-center min-h-[50vh] text-center px-6">
                <div className="w-16 h-16 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-6"></div>
                <h2 className="text-xl font-bold text-slate-800 mb-2">Analysing Anatomy...</h2>
                <p className="text-slate-500 text-sm">Our AI is designing your {selection.treatment?.title} using {selection.material?.title} parameters.</p>
              </div>
            ) : error ? (
               /* ERROR STATE */
               <div className="flex-1 flex flex-col items-center justify-center min-h-[50vh] text-center px-6">
                 <div className="w-16 h-16 bg-red-100 text-red-500 rounded-full flex items-center justify-center mb-4">
                   <AlertCircle className="w-8 h-8" />
                 </div>
                 <h2 className="text-xl font-bold text-slate-800 mb-2">Simulation Failed</h2>
                 <p className="text-slate-500 mb-6">{error}</p>
                 <button onClick={() => setStep(4)} className="px-6 py-3 bg-slate-900 text-white rounded-lg font-medium">Try Another Photo</button>
               </div>
            ) : (
              /* LEAD GATE STATE */
              <div className="flex-1 flex flex-col justify-center px-4">
                 <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-xl text-center">
                    <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                      <Check className="w-8 h-8" />
                    </div>
                    <h2 className="text-2xl font-bold text-slate-900 mb-2">Your Smile is Ready!</h2>
                    <p className="text-slate-500 mb-6 text-sm">
                      We have generated your high-resolution {selection.treatment?.title} simulation. Enter your details to unlock the result and get a cost estimate.
                    </p>

                    <div className="space-y-3 text-left mb-6">
                      <div>
                        <label className="text-xs font-semibold text-slate-700 ml-1">Full Name</label>
                        <div className="relative mt-1">
                          <User className="absolute left-3 top-3 w-5 h-5 text-slate-400" />
                          <input type="text" className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none transition-all" placeholder="John Doe" />
                        </div>
                      </div>
                      <div>
                        <label className="text-xs font-semibold text-slate-700 ml-1">Email Address</label>
                        <div className="relative mt-1">
                          <Mail className="absolute left-3 top-3 w-5 h-5 text-slate-400" />
                          <input type="email" className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none transition-all" placeholder="john@example.com" />
                        </div>
                      </div>
                    </div>

                    <button 
                      onClick={nextStep}
                      className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-lg shadow-lg shadow-blue-200 transition-all flex items-center justify-center space-x-2"
                    >
                      <span>Unlock My New Smile</span>
                      <ChevronRight className="w-5 h-5" />
                    </button>

                    <button 
                      onClick={nextStep}
                      className="mt-4 text-xs text-slate-400 hover:text-slate-600 underline decoration-slate-300 underline-offset-2"
                    >
                      Demo Mode: Skip this step
                    </button>
                 </div>
              </div>
            )}
          </div>
        )}

        {/* --- STEP 7: FINAL RESULT --- */}
        {step === 7 && (
          <div className="animate-fade-in h-full flex flex-col">
              <div className="flex flex-col h-full">
                <div className="flex items-center justify-between mb-4">
                  <h1 className="text-2xl font-bold text-slate-900">Your New Smile</h1>
                  <span className="bg-green-100 text-green-700 text-xs font-bold px-2 py-1 rounded-full uppercase tracking-wide">AI Simulation</span>
                </div>

                {/* Before / After Slider */}
                <div className="mb-6">
                  {image && resultImage && <BeforeAfterSlider original={image} simulation={resultImage} />}
                  <div className="flex justify-between mt-2 text-xs text-slate-400 px-1">
                    <span>Original</span>
                    <span>Simulation</span>
                  </div>
                </div>

                <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-6">
                   <div className="flex items-start space-x-3">
                     <Info className="w-5 h-5 text-blue-500 mt-0.5 shrink-0" />
                     <div className="text-xs text-slate-600 leading-relaxed">
                       <strong>Visualisation Only:</strong> This is an AI-generated preview for aesthetic purposes. It is not a clinical guarantee or a medical diagnosis. A dentist must assess your oral health.
                     </div>
                   </div>
                </div>

                <div className="space-y-3 mt-auto">
                   <button 
                    onClick={() => setStep(0)}
                    className="w-full py-3 bg-white border border-slate-300 text-slate-700 rounded-xl font-semibold hover:bg-slate-50 transition-colors flex items-center justify-center"
                   >
                     <RefreshCw className="w-4 h-4 mr-2" /> Start Over
                   </button>
                   <button className="w-full py-4 bg-blue-900 text-white rounded-xl font-bold shadow-lg shadow-blue-900/20 hover:bg-blue-800 transition-colors">
                     Get Free Treatment Plan
                   </button>
                </div>
              </div>
          </div>
        )}

      </main>
    </div>
  );
}

