import React, { useState, useRef, useEffect, ChangeEvent } from 'react';
import { Camera, Upload, RefreshCw } from 'lucide-react';

interface CameraModuleProps {
  onCapture: (imgData: string) => void;
}

const CameraModule: React.FC<CameraModuleProps> = ({ onCapture }) => {
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('user'); 
  const videoRef = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    return () => stopCamera();
  }, []);

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  const startCamera = async (overrideMode?: 'user' | 'environment') => {
    const modeToUse = overrideMode || facingMode;

    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }

    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Browser does not support camera access");
      }

      const constraints = { 
        video: { 
          facingMode: modeToUse 
        },
        audio: false
      };

      const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(mediaStream);

      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        try {
          await videoRef.current.play();
        } catch (playErr) {
          console.error("Video play error:", playErr);
        }
      }
    } catch (err) {
      console.error("Camera error:", err);
      alert("Unable to access camera. Please check permissions or use Upload.");
    }
  };

  const toggleCamera = () => {
    const newMode = facingMode === 'user' ? 'environment' : 'user';
    setFacingMode(newMode);
    startCamera(newMode);
  };

  const takePhoto = () => {
    if (!videoRef.current) return;
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    const ctx = canvas.getContext('2d');

    if (!ctx) return;

    if (facingMode === 'user') {
      ctx.translate(canvas.width, 0);
      ctx.scale(-1, 1);
    }

    ctx.drawImage(videoRef.current, 0, 0);
    const dataUrl = canvas.toDataURL('image/jpeg');
    stopCamera();
    onCapture(dataUrl);
  };

  const handleFileUpload = (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (typeof reader.result === 'string') {
          onCapture(reader.result);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="absolute inset-0 bg-black z-50 flex flex-col animate-fade-in overflow-hidden">
      {/* Video Preview Area - Flex Grow to take available space */}
      <div className="relative flex-1 bg-black overflow-hidden flex items-center justify-center min-h-0">
        {stream ? (
          <video 
            ref={videoRef} 
            playsInline 
            muted 
            className={`absolute inset-0 w-full h-full object-cover ${facingMode === 'user' ? 'scale-x-[-1]' : ''}`}
          />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center text-slate-500 flex-col space-y-4 p-4 text-center">
             <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center text-slate-700">
               <Camera className="w-8 h-8" />
             </div>
             <p className="max-w-xs text-sm">Camera inactive. Click "Enable Camera" or upload a photo.</p>
          </div>
        )}

        <div className="absolute inset-0 pointer-events-none">
           <div className="absolute inset-0 bg-black/50" 
                style={{ 
                  maskImage: 'radial-gradient(ellipse 70% 65% at center, transparent 1%, black 100%)',
                  WebkitMaskImage: 'radial-gradient(ellipse 70% 65% at center, transparent 1%, black 100%)' 
                }}>
           </div>

           <div className="absolute inset-0 flex items-center justify-center">
             {/* Responsive Overlay Box */}
             <div className="w-[75%] max-w-[320px] aspect-[3/4] border-2 border-white/30 rounded-[50%] relative">
                {stream && (
                  <div className="absolute top-0 left-0 right-0 h-1 bg-blue-500/80 shadow-[0_0_15px_rgba(59,130,246,0.8)] animate-scan"></div>
                )}
                <div className="absolute top-6 left-1/2 -translate-x-1/2 text-white/90 font-medium text-xs drop-shadow-md whitespace-nowrap">
                   Center your smile
                </div>
             </div>
           </div>
        </div>
      </div>

      {/* Control Bar - Fixed Height */}
      <div className="bg-black/90 px-6 py-8 flex items-center justify-between space-x-4 flex-none">
         <button 
           onClick={() => fileInputRef.current?.click()}
           className="p-4 rounded-full bg-white/10 text-white hover:bg-white/20 transition-all active:scale-95"
           aria-label="Upload Photo"
         >
           <Upload className="w-6 h-6" />
         </button>
         <input 
           type="file" 
           ref={fileInputRef} 
           className="hidden" 
           accept="image/*" 
           onChange={handleFileUpload}
         />

         {stream ? (
           <button 
             onClick={takePhoto}
             className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center relative group active:scale-95 transition-transform"
             aria-label="Take Photo"
           >
             <div className="w-16 h-16 bg-white rounded-full group-hover:scale-90 transition-transform" />
           </button>
         ) : (
           <button 
             onClick={() => startCamera()}
             className="px-6 py-3 bg-blue-600 rounded-full text-white font-bold whitespace-nowrap active:scale-95 transition-transform"
           >
             Enable Camera
           </button>
         )}

         {stream ? (
           <button 
             onClick={toggleCamera}
             className="p-4 rounded-full bg-white/10 text-white hover:bg-white/20 transition-all active:scale-95"
             aria-label="Switch Camera"
           >
             <RefreshCw className="w-6 h-6" />
           </button>
         ) : (
           <div className="w-14" />
         )}
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 10%; opacity: 0; }
          10% { opacity: 1; }
          90% { opacity: 1; }
          100% { top: 90%; opacity: 0; }
        }
        .animate-scan {
          animation: scan 3s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default CameraModule;

import React, { useState, useEffect } from 'react';
import { 
  Check, ChevronRight, RefreshCw, Sparkles, AlertCircle, ArrowLeft, 
  Lock, Info, ScanFace, User, Mail, Shield, Key
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

import OptionCard from './components/OptionCard';
import ReviewRow from './components/ReviewRow';
import BeforeAfterSlider from './components/BeforeAfterSlider';
import CameraModule from './components/CameraModule';
import { TREATMENTS, MATERIALS, SHADES } from './constants';
import { SelectionState, Treatment, Material, Shade } from './types';

export default function App() {
  const [step, setStep] = useState(0); 
  const [selection, setSelection] = useState<SelectionState>({ treatment: null, material: null, shade: null });
  const [hasConsented, setHasConsented] = useState(false);
  const [image, setImage] = useState<string | null>(null); 
  const [isSimulating, setIsSimulating] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [apiKeySelected, setApiKeySelected] = useState(false);

  // Check for API Key on mount
  useEffect(() => {
    const checkApiKey = async () => {
      if (typeof window !== 'undefined' && (window as any).aistudio) {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        setApiKeySelected(hasKey);
      }
    };
    checkApiKey();
  }, []);

  const handleStartFlow = async () => {
    if (!apiKeySelected) {
      if (typeof window !== 'undefined' && (window as any).aistudio) {
        try {
          await (window as any).aistudio.openSelectKey();
          setApiKeySelected(true);
        } catch (e) {
          console.error("API Key selection failed", e);
        }
      } else {
        console.warn("window.aistudio not found, proceeding (might fail if key not in env)");
        nextStep();
      }
    } else {
      nextStep();
    }
  };

  const handleSelect = (key: keyof SelectionState, value: Treatment | Material | Shade) => {
    setSelection(prev => ({ ...prev, [key]: value }));
    nextStep();
  };

  const nextStep = () => setStep(prev => prev + 1);
  const prevStep = () => setStep(prev => Math.max(0, prev - 1));

  const handleImageCapture = (imgData: string) => {
    setImage(imgData);
    nextStep();
  };

  const generateSimulation = async () => {
    setIsSimulating(true);
    setError(null);

    try {
      if (!image) throw new Error("No image data available to simulate.");

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const treatment = selection.treatment;
      const material = selection.material;
      const shade = selection.shade;

      const isStructural = treatment?.structuralChange ?? true;

      let anatomicalDirectives = "";

      if (!isStructural) {
        // NON-STRUCTURAL (e.g. Whitening): Strict preservation
        anatomicalDirectives = `
          [MODE: TEXTURE_PRESERVING_RECOLOR]
          1. GEOMETRY LOCK: The shape, outline, size, rotation, and position of every tooth MUST remain pixel-perfect identical to the input.
          2. DEFECT PRESERVATION: Do not fix chips, gaps (diastema), or misalignment. Preserve them exactly.
          3. SURFACE MAPPING: Retain the original texture, wetness, and light reflections.
          4. ACTION: Only adjust the color values (Whiter/Brighter) and reduce yellow saturation of the enamel area.
        `;
      } else {
        // STRUCTURAL (e.g. Veneers, Implants): Cosmetic improvement
        anatomicalDirectives = `
          [MODE: COSMETIC_RECONSTRUCTION]
          1. IDEALIZATION: Correct the shape and alignment of visible teeth to achieve symmetry and Golden Ratio proportions.
          2. BOUNDARY CONSTRAINT: All changes must occur strictly within the open mouth area. Do not modify the lips or skin.
          3. ALIGNMENT: Straighten crooked teeth while respecting the natural arch.
        `;
      }

      const prompt = `
        ** SYSTEM ROLE **
        You are an expert Dental Simulation AI. Your task is to generate a realistic "After" photo.

        ** INPUT ANALYSIS **
        Source Image: User's face.

        ** STRICT IDENTITY & FRAMING PROTECTION (CRITICAL) **
        1. DO NOT ZOOM OR CROP. The output image must have the EXACT same field of view, zoom level, and framing as the input. 
        2. PIXEL ALIGNMENT: The user's eyes, nose, ears, hair, chin, and lips must align perfectly with the original image.
        3. LIPS: The mouth opening and lip shape MUST NOT CHANGE. The new teeth must fit inside the existing lip frame.

        ** PROCEDURE CONFIGURATION **
        Type: ${treatment?.title}
        Context: ${treatment?.promptContext}
        Material: ${material?.title} (${material?.promptMod})
        Target Shade: ${shade?.title} (${shade?.promptMod})

        ** GENERATION DIRECTIVES **
        ${anatomicalDirectives}

        ** OUTPUT QUALITY **
        - Photorealistic Clinical Photography
        - Natural Enamel translucency and gloss
      `;

      // Extract MIME type and base64 data
      const matches = image.match(/^data:(.+);base64,(.+)$/);
      let mimeType = 'image/jpeg';
      let base64Data = image;

      if (matches && matches.length === 3) {
        mimeType = matches[1];
        base64Data = matches[2];
      } else {
        base64Data = image.replace(/^data:image\/\w+;base64,/, "");
      }

      // Using Gemini 3 Pro Image Preview (Nano Banana Pro) for best quality
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: mimeType,
                data: base64Data
              }
            },
            {
              text: prompt
            }
          ]
        },
        config: {
          imageConfig: {
            // Using 3:4 aspect ratio to match typical portrait selfies and prevent cropping/shifting
            aspectRatio: '3:4',
            imageSize: '1K' 
          }
        }
      });

      let generatedBase64 = null;

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            generatedBase64 = part.inlineData.data;
            const outMime = part.inlineData.mimeType || 'image/png';
            setResultImage(`data:${outMime};base64,${generatedBase64}`);
            break;
          }
        }
      }

      if (!generatedBase64) {
        const textOutput = response.text;
        if (textOutput) {
             throw new Error("AI Refusal: " + textOutput);
        }
        throw new Error("No image generated. The model might have filtered the response due to safety settings.");
      }

    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("API key not valid") || err.message?.includes("API_KEY")) {
         setError("Invalid API Key. Please restart and select a valid Paid API Key.");
         setApiKeySelected(false);
      } else {
         setError("Simulation failed. " + (err.message || "Unknown error"));
      }
    } finally {
      setIsSimulating(false);
    }
  };

  // Main Container is fixed h-screen to prevent global scroll
  return (
