// --- SIMULATION LOGIC ---

async function generateSimulation() {
  els.loadingState.classList.remove('hidden');
  els.errorState.classList.add('hidden');
  els.successState.classList.add('hidden');

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // We use gemini-2.5-flash-image for standard image generation/editing
    const modelId = 'gemini-2.5-flash-image';

    const prompt = buildPrompt();

    // Process base64
    const matches = state.image.match(/^data:(.+);base64,(.+)$/);
    let mimeType = 'image/jpeg';
    let base64Data = state.image;
    if (matches && matches.length === 3) {
      mimeType = matches[1];
      base64Data = matches[2];
    } else {
      base64Data = state.image.replace(/^data:image\/\w+;base64,/, "");
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: prompt }
        ]
      }
    });

    // Extract Result
    let generatedBase64 = null;
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          generatedBase64 = part.inlineData.data;
          const outMime = part.inlineData.mimeType || 'image/png';
          state.resultImage = `data:${outMime};base64,${generatedBase64}`;
          break;
        }
      }
    }

    if (!generatedBase64) {
      throw new Error("No image generated. The AI might have refused the request.");
    }

    // Success
    els.loadingState.classList.add('hidden');
    els.successState.classList.remove('hidden');

  } catch (err: any) {
    console.error(err);
    els.loadingState.classList.add('hidden');
    els.errorState.classList.remove('hidden');
    els.errorMessage.innerText = err.message || "Unknown error occurred.";
  }
}

function buildPrompt() {
  const { treatment, material, shade } = state.selection;
  const isStructural = treatment?.structuralChange ?? true;

  let directives = "";
  if (!isStructural) {
     directives = `[MODE: TEXTURE_PRESERVING_RECOLOR]
      1. GEOMETRY LOCK: The shape, outline, size, rotation, and position of every tooth MUST remain pixel-perfect identical to the input.
      2. DEFECT PRESERVATION: Do not fix chips, gaps, or misalignment.
      3. ACTION: Only adjust the color values (Whiter/Brighter).`;
  } else {
     directives = `[MODE: COSMETIC_RECONSTRUCTION]
      1. IDEALIZATION: Correct the shape and alignment of visible teeth to achieve symmetry.
      2. BOUNDARY CONSTRAINT: Changes must occur strictly within the open mouth area. DO NOT modify lips or skin.`;
  }

  return `
    ** SYSTEM ROLE **
    You are an expert Dental Simulation AI. Generate a realistic "After" photo.

    ** STRICT IDENTITY & FRAMING PROTECTION **
    1. DO NOT ZOOM OR CROP. The output must have the EXACT same field of view and framing.
    2. PIXEL ALIGNMENT: Eyes, nose, skin, and LIPS must match perfectly.
    3. The new teeth must fit inside the existing lip frame.

    ** CONFIGURATION **
    Type: ${treatment?.title} (${treatment?.promptContext})
    Material: ${material?.title}
    Shade: ${shade?.title}

    ${directives}

    Output: Photorealistic.
  `;
}

// --- SLIDER LOGIC ---

function initSlider() {
  const container = els.sliderContainer;
  const handle = els.sliderHandle;
  const beforeContainer = els.sliderBeforeContainer;

  if (!container) return;

  const update = (x: number) => {
    const rect = container.getBoundingClientRect();
    const pos = Math.max(0, Math.min(x - rect.left, rect.width));
    const pct = (pos / rect.width) * 100;

    handle.style.left = `${pct}%`;
    beforeContainer.style.clipPath = `inset(0 ${100 - pct}% 0 0)`;
  };

  const onMove = (e: MouseEvent) => {
    if (e.buttons === 1) update(e.clientX);
  };
  const onTouch = (e: TouchEvent) => {
    update(e.touches[0].clientX);
  };

  container.onmousedown = (e: MouseEvent) => update(e.clientX);
  container.onmousemove = onMove;
  container.ontouchmove = onTouch;
}

