// --- SIMULATION LOGIC ---

async function generateSimulation() {
  els.loadingState.classList.remove('hidden');
  els.errorState.classList.add('hidden');

  // Note: We do not show successState anymore, we jump to Result (Step 7) which is locked

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Using gemini-2.5-flash-image
    const modelId = 'gemini-2.5-flash-image';

    const prompt = buildPrompt();

    // Process base64
    const matches = state.image.match(/^data:(.+);base64,(.+)$/);
    let mimeType = 'image/jpeg';
    let base64Data = state.image;
    if (matches && matches.length === 3) {
      mimeType = matches[1];
      base64Data = matches[2];
    } else {
      base64Data = state.image.replace(/^data:image\/\w+;base64,/, "");
    }

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: prompt }
        ]
      }
    });

    // Extract Result
    let generatedBase64 = null;
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          generatedBase64 = part.inlineData.data;
          const outMime = part.inlineData.mimeType || 'image/png';
          state.resultImage = `data:${outMime};base64,${generatedBase64}`;
          break;
        }
      }
    }

    if (!generatedBase64) {
      throw new Error("No image generated. The AI might have refused the request due to safety filters.");
    }

    // Success -> Jump to Step 7 (Locked)
    state.step = 7;
    state.isLocked = true;
    render();

  } catch (err: any) {
    console.error(err);
    els.loadingState.classList.add('hidden');
    els.errorState.classList.remove('hidden');
    els.errorMessage.innerText = err.message || "Unknown error occurred.";
  }
}

function buildPrompt() {
  const { treatment, material, shade } = state.selection;

  // Highly constrained prompt for Gemini Flash Image
  return `
    ** ROLE **
    Professional Dental Retoucher.

    ** TASK **
    Edit the teeth in the image to simulate a dental treatment.

    ** CRITICAL CONSTRAINTS (MUST FOLLOW) **
    1. OUTPUT DIMENSIONS: The output image must match the input image dimensions and framing EXACTLY.
    2. NO CROPPING/ZOOMING: Do not zoom in on the mouth. Keep the full face or original framing visible.
    3. PRESERVE ANATOMY: Do not change the lips, gums, nose, skin tone, or face shape. Only modify the teeth enamel.
    4. MOUTH SHAPE: Keep the mouth opening and lip position exactly as they are in the original.

    ** TREATMENT DETAILS **
    Procedure: ${treatment?.title}
    Context: ${treatment?.promptContext}
    Material: ${material?.title}
    Shade: ${shade?.title} (${shade?.promptMod})

    Output: Photorealistic, natural lighting, high resolution.
  `;
}

// --- SLIDER LOGIC ---

function initSlider() {
  const container = els.sliderContainer;
  const handle = els.sliderHandle;
  const beforeContainer = els.sliderBeforeContainer;

  if (!container) return;

  const update = (x: number) => {
    const rect = container.getBoundingClientRect();
    const pos = Math.max(0, Math.min(x - rect.left, rect.width));
    const pct = (pos / rect.width) * 100;

    handle.style.left = `${pct}%`;
    beforeContainer.style.clipPath = `inset(0 ${100 - pct}% 0 0)`;
  };

  const onMove = (e: MouseEvent) => {
    if (e.buttons === 1) update(e.clientX);
  };
  const onTouch = (e: TouchEvent) => {
    update(e.touches[0].clientX);
  };

  container.onmousedown = (e: MouseEvent) => update(e.clientX);
  container.onmousemove = onMove;
  container.ontouchmove = onTouch;
}

