// --- INITIALIZATION ---

document.addEventListener('DOMContentLoaded', () => {
  if (typeof lucide !== 'undefined') lucide.createIcons();
  render();
});

// --- RENDER LOGIC ---

function render() {
  // Update Header Visibility
  if (state.step > 0) {
    els.header.classList.remove('hidden');
    // Update Progress Bar
    const pct = (state.step / 7) * 100;
    els.progressBar.style.width = `${pct}%`;
  } else {
    els.header.classList.add('hidden');
  }

  // Update Back Button
  if (state.step > 1 && state.step < 7) {
    els.backBtnContainer.classList.remove('hidden');
  } else {
    els.backBtnContainer.classList.add('hidden');
  }

  // Toggle Steps
  document.querySelectorAll('.step-container').forEach(el => el.classList.add('hidden'));
  const currentStepEl = document.getElementById(`step-${state.step}`);
  if (currentStepEl) currentStepEl.classList.remove('hidden');

  // Step Specific Renders
  if (state.step === 1) renderTreatments();
  if (state.step === 2) renderMaterials();
  if (state.step === 3) renderShades();
  if (state.step === 5) renderReview();
  if (state.step === 7) renderResult();

  // Refresh Icons
  if (typeof lucide !== 'undefined') lucide.createIcons();
}

function renderTreatments() {
  els.treatmentList.innerHTML = '';
  TREATMENTS.forEach(t => {
    const btn = createOptionCard(t.title, t.desc, t.icon, () => {
      state.selection.treatment = t;
      nextStep();
    });
    els.treatmentList.appendChild(btn);
  });
}

function renderMaterials() {
  els.materialList.innerHTML = '';
  const list = (state.selection.treatment && MATERIALS[state.selection.treatment.id]) 
    ? MATERIALS[state.selection.treatment.id] 
    : MATERIALS.veneers;

  list.forEach((m: any) => {
    const btn = createOptionCard(m.title, m.desc, null, () => {
      state.selection.material = m;
      nextStep();
    });
    els.materialList.appendChild(btn);
  });
}

function renderShades() {
  els.shadeList.innerHTML = '';
  SHADES.forEach(s => {
    const btn = document.createElement('button');
    btn.className = "group relative flex items-center p-4 bg-white rounded-xl border border-slate-200 shadow-sm hover:border-blue-500 hover:shadow-md transition-all text-left";

    // Color circle
    const colorHex = s.id === 'bl1' ? '#ffffff' : s.id === 'a2' ? '#fefce0' : '#fffdf5';

    btn.innerHTML = `
      <div class="w-12 h-12 rounded-full border-2 border-slate-100 shadow-inner mr-4 flex-shrink-0 bg-gradient-to-br from-white to-slate-100" style="background-color: ${colorHex}"></div>
      <div>
        <div class="font-semibold text-slate-900">${s.title}</div>
        <div class="text-sm text-slate-500">${s.desc}</div>
      </div>
      <i data-lucide="chevron-right" class="w-5 h-5 ml-auto text-slate-300 group-hover:text-blue-500"></i>
    `;
    btn.onclick = () => {
      state.selection.shade = s;
      nextStep();
    };
    els.shadeList.appendChild(btn);
  });
}

function createOptionCard(title: string, desc: string, iconName: string | null, onClick: () => void) {
  const btn = document.createElement('button');
  btn.className = "w-full text-left p-4 bg-white rounded-xl border border-slate-200 shadow-sm hover:border-blue-500 hover:ring-1 hover:ring-blue-500 transition-all group";

  let iconHtml = `<div class="w-2 h-2 rounded-full bg-current"></div>`;
  if (iconName === 'crown') {
    iconHtml = `<div class="w-6 h-6 font-bold text-center border rounded-full text-xs flex items-center justify-center border-current">Zr</div>`;
  } else if (iconName) {
    iconHtml = `<i data-lucide="${iconName}" class="w-6 h-6"></i>`;
  }

  btn.innerHTML = `
    <div class="flex items-start space-x-4">
      <div class="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center flex-shrink-0 mt-1 group-hover:bg-blue-600 group-hover:text-white transition-colors">
        ${iconHtml}
      </div>
      <div class="flex-1">
        <h3 class="font-semibold text-slate-900 text-lg">${title}</h3>
        <p class="text-sm text-slate-500 leading-relaxed">${desc}</p>
      </div>
      <i data-lucide="chevron-right" class="w-5 h-5 text-slate-300 self-center group-hover:text-blue-500"></i>
    </div>
  `;
  btn.onclick = onClick;
  return btn;
}

function renderReview() {
  els.reviewDetails.innerHTML = `
    <div class="flex justify-between items-center border-b border-slate-100 pb-2"><span class="text-slate-500 text-sm">Treatment</span><span class="font-medium text-slate-900 text-sm">${state.selection.treatment?.title || '-'}</span></div>
    <div class="flex justify-between items-center border-b border-slate-100 pb-2"><span class="text-slate-500 text-sm">Material</span><span class="font-medium text-slate-900 text-sm">${state.selection.material?.title || '-'}</span></div>
    <div class="flex justify-between items-center border-b border-slate-100 pb-0"><span class="text-slate-500 text-sm">Shade</span><span class="font-medium text-slate-900 text-sm">${state.selection.shade?.title || '-'}</span></div>
  `;
  els.reviewImage.src = state.image;
}

function renderResult() {
  els.sliderBefore.src = state.image;
  els.sliderAfter.src = state.resultImage;

  // Handle Lead Gate Visibility
  if (state.isLocked) {
    els.leadGateOverlay.classList.remove('opacity-0', 'pointer-events-none');
    els.leadGateOverlay.classList.add('opacity-100');
  } else {
    els.leadGateOverlay.classList.remove('opacity-100');
    els.leadGateOverlay.classList.add('opacity-0', 'pointer-events-none');
  }

  initSlider();
}

// --- NAVIGATION & ACTIONS ---

function nextStep() {
  state.step++;
  render();
}

function prevStep() {
  state.step = Math.max(0, state.step - 1);
  render();
}

els.startBtn.onclick = nextStep;
els.backBtn.onclick = prevStep;
els.generateBtn.onclick = async () => {
  nextStep();
  await generateSimulation();
};

els.unlockBtn.onclick = () => {
  // Simple validation or simulate API call
  const inputs = els.leadGateOverlay.querySelectorAll('input');
  let valid = true;
  inputs.forEach(input => {
    if(!(input as HTMLInputElement).value) {
      valid = false;
      input.classList.add('border-red-500');
    } else {
      input.classList.remove('border-red-500');
    }
  });

  if (valid) {
    state.isLocked = false;
    renderResult();
  }
};

els.skipBtn.onclick = () => {
  state.isLocked = false;
  renderResult();
}

els.restartBtn.onclick = () => {
  state.step = 0;
  state.image = null;
  state.resultImage = null;
  state.selection = { treatment: null, material: null, shade: null };
  state.hasConsented = false;
  state.isLocked = true;
  els.consentCheckbox.checked = false;
  els.uploadSection.classList.add('opacity-50', 'grayscale', 'pointer-events-none', 'filter');
  render();
};
els.retryBtn.onclick = () => {
  state.step = 4;
  render();
}

// Consent Logic
els.consentCheckbox.onchange = (e: Event) => {
  state.hasConsented = (e.target as HTMLInputElement).checked;
  if (state.hasConsented) {
    els.uploadSection.classList.remove('opacity-50', 'grayscale', 'pointer-events-none', 'filter');
  } else {
    els.uploadSection.classList.add('opacity-50', 'grayscale', 'pointer-events-none', 'filter');
  }
};

// Image Upload Logic
els.imageUpload.onchange = (e: Event) => {
  const file = (e.target as HTMLInputElement).files?.[0];
  if (file) {
    const reader = new FileReader();
    reader.onloadend = () => {
      state.image = reader.result;
      nextStep(); // Go to review
    };
    reader.readAsDataURL(file);
  }
};

